     /// Build a startup message (no type byte, includes protocol version).
     fn build_startup_message(&mut self) -> Result<Vec<u8>, PgError> {
         let payload_len = self.buf.len().saturating_add(4);
-        let len: i32 = i32::try_from(payload_len)
